const { sendError } = require('../../lib/errors');
const projectsTasks = {};

exports.createTask = async (taskData) => {
  if (!taskData.name) throw new BadRequestError('Invalid task data');
  const projectId = taskData.projectId;
  if (!projectsTasks[projectId]) projectsTasks[projectId] = [];
  const newTask = { id: randomUUID(), status: 'todo', ...taskData };
  projectsTasks[projectId].push(newTask);
  return newTask;
};
exports.getTasksByStatus = async (projectId, status) => {
  if (!projectsTasks[projectId]) throw new NotFoundError('Project not found');
  const tasks = projectsTasks[projectId].filter(task => task.status === status);
  return tasks;
};
